namespace sv_3e0184cba56542da8d906a5e723bca4c;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public class ThemeInfo
{
    public ThemeMode Theme { get; set; } = ThemeMode.System;
    public string AccentColor { get; set; } = "#0d6efd";
}

using Microsoft.AspNetCore.Components;

namespace sv_3e0184cba56542da8d906a5e723bca4c;

/// <summary>
/// Scoped service that owns theme state and its CascadingValueSource.
/// Per-circuit lifetime ensures each user has independent state.
/// </summary>
public class ThemeService
{
    public CascadingValueSource<ThemeInfo> CascadingSource { get; }
    public ThemeInfo Current { get; }

    public ThemeService()
    {
        Current = new ThemeInfo();
        CascadingSource = new CascadingValueSource<ThemeInfo>(Current, isFixed: false);
    }

    public async Task SetThemeAsync(ThemeMode theme)
    {
        Current.Theme = theme;
        await CascadingSource.NotifyChangedAsync(Current);
    }

    public async Task SetAccentColorAsync(string color)
    {
        Current.AccentColor = color;
        await CascadingSource.NotifyChangedAsync(Current);
    }
}

@rendermode InteractiveServer

<span class="theme-indicator" style="color: @Theme?.AccentColor;">
    @GetThemeIcon() @Theme?.Theme.ToString()
</span>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetThemeIcon() => Theme?.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        _ => "💻"
    };
}

@rendermode InteractiveServer
@inject ThemeService ThemeService

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Toggle theme">
    @GetIcon()
</button>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private string GetIcon() => Theme?.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        _ => "💻"
    };

    private async Task CycleTheme()
    {
        var next = Theme?.Theme switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            _ => ThemeMode.Light
        };
        await ThemeService.SetThemeAsync(next);
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeService

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card" style="max-width: 400px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@Theme?.Theme" @onchange="OnThemeChanged">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    <option value="@mode">@mode</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@Theme?.AccentColor" @onchange="OnAccentColorChanged" />
                <span style="color: @Theme?.AccentColor;">@Theme?.AccentColor</span>
            </div>
        </div>

        <div class="mt-3 p-2 border rounded" style="border-color: @Theme?.AccentColor !important;">
            <small class="text-muted">Preview:</small>
            <span style="color: @Theme?.AccentColor;">
                @GetThemeIcon() @Theme?.Theme mode with accent @Theme?.AccentColor
            </span>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo? Theme { get; set; }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<ThemeMode>(e.Value?.ToString(), out var mode))
        {
            await ThemeService.SetThemeAsync(mode);
        }
    }

    private async Task OnAccentColorChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString();
        if (!string.IsNullOrEmpty(color))
        {
            await ThemeService.SetAccentColorAsync(color);
        }
    }

    private string GetThemeIcon() => Theme?.Theme switch
    {
        ThemeMode.Light => "☀️",
        ThemeMode.Dark => "🌙",
        _ => "💻"
    };
}

